package com.example.woofie

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import com.example.woofie.data.WoofieRepository
import com.example.woofie.model.Profession
import com.example.woofie.model.UserProfile
import com.example.woofie.ui.HomeFragment
import com.example.woofie.ui.LessonFragment
import com.example.woofie.ui.LessonPathFragment
import com.example.woofie.ui.OnboardingFragment
import com.example.woofie.ui.ProgressFragment

class MainActivity : AppCompatActivity(),
    OnboardingFragment.Listener,
    HomeFragment.Listener,
    LessonPathFragment.Listener,
    LessonFragment.Listener,
    ProgressFragment.Listener {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        if (savedInstanceState == null) {
            if (WoofieRepository.profile == null) {
                showOnboarding()
            } else {
                showHome()
            }
        }
    }

    override fun onOnboardingCompleted(profession: Profession, level: String) {
        WoofieRepository.profile = UserProfile(
            profession = profession,
            level = level,
            streak = 1,
            completedLessons = 0,
            xp = 0
        )
        showHome()
    }

    override fun onStartLesson() {
        showLessonPath()
    }

    override fun onOpenLessonFromPath() {
        showLesson()
    }

    override fun onOpenProgress() {
        showProgress()
    }

    override fun onLessonFinished(correctAnswers: Int, totalAnswers: Int) {
        val outcome = WoofieRepository.registerLessonResult(
            correctAnswers = correctAnswers,
            totalAnswers = totalAnswers
        )
        showProgress(
            resultLabel = outcome.scoreLabel,
            earnedXp = outcome.earnedXp,
            passedLesson = outcome.passed
        )
    }

    override fun onBackToHome() {
        showHome()
    }

    override fun onRestartPlan() {
        WoofieRepository.profile = null
        WoofieRepository.lastResultLabel = null
        WoofieRepository.lastEarnedXp = 0
        WoofieRepository.lastLessonPassed = false
        showOnboarding()
    }

    private fun showOnboarding() {
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, OnboardingFragment())
            .commit()
    }

    private fun showHome() {
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, HomeFragment())
            .commit()
    }

    private fun showLesson() {
        supportFragmentManager.beginTransaction()
            .setCustomAnimations(
                R.anim.woofie_enter_right,
                R.anim.woofie_exit_left,
                R.anim.woofie_enter_left,
                R.anim.woofie_exit_right
            )
            .replace(R.id.fragmentContainer, LessonFragment())
            .addToBackStack(null)
            .commit()
    }

    private fun showLessonPath() {
        supportFragmentManager.beginTransaction()
            .setCustomAnimations(
                R.anim.woofie_enter_right,
                R.anim.woofie_exit_left,
                R.anim.woofie_enter_left,
                R.anim.woofie_exit_right
            )
            .replace(R.id.fragmentContainer, LessonPathFragment())
            .addToBackStack(null)
            .commit()
    }

    private fun showProgress(
        resultLabel: String? = null,
        earnedXp: Int = WoofieRepository.lastEarnedXp,
        passedLesson: Boolean = WoofieRepository.lastLessonPassed
    ) {
        val fragment = ProgressFragment.newInstance(
            resultLabel = resultLabel ?: WoofieRepository.lastResultLabel.orEmpty(),
            earnedXp = earnedXp,
            passedLesson = passedLesson
        )

        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, fragment)
            .addToBackStack(null)
            .commit()
    }
}

package com.example.woofie

import android.os.Bundle
import android.view.View
import android.view.Menu
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.example.woofie.data.WoofieRepository
import com.example.woofie.model.Profession
import com.example.woofie.model.UserProfile
import com.example.woofie.ui.HomeFragment
import com.example.woofie.ui.LessonFragment
import com.example.woofie.ui.LessonPathFragment
import com.example.woofie.ui.OnboardingFragment
import com.example.woofie.ui.PracticeCenterFragment
import com.example.woofie.ui.ProgressFragment
import com.example.woofie.ui.VocabularyFragment

class MainActivity : AppCompatActivity(),
    OnboardingFragment.Listener,
    HomeFragment.Listener,
    LessonPathFragment.Listener,
    PracticeCenterFragment.Listener,
    LessonFragment.Listener,
    ProgressFragment.Listener {

    private lateinit var bottomNavigation: BottomNavigationView
    private var suppressNavSelectionCallback: Boolean = false

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
        bottomNavigation = findViewById(R.id.bottomNavigation)
        setupBottomNavigationMenu()

        bottomNavigation.setOnItemSelectedListener { item ->
            if (suppressNavSelectionCallback) return@setOnItemSelectedListener true
            when (item.itemId) {
                R.id.navigation_home -> showHome()
                R.id.navigation_path -> showLessonPath()
                R.id.navigation_practice -> showPracticeCenter()
                R.id.navigation_vocabulary -> showVocabulary()
                R.id.navigation_progress -> showProgress()
                else -> return@setOnItemSelectedListener false
            }
            true
        }

        if (savedInstanceState == null) {
            if (WoofieRepository.profile == null) {
                showOnboarding()
            } else {
                showMainNavigation()
                selectBottomTab(R.id.navigation_home)
            }
        } else {
            bottomNavigation.visibility = if (WoofieRepository.profile == null) View.GONE else View.VISIBLE
        }
    }

    override fun onOnboardingCompleted(profession: Profession, level: String) {
        WoofieRepository.profile = UserProfile(
            profession = profession,
            level = level,
            streak = 1,
            completedLessons = 0,
            xp = 0
        )
        showMainNavigation()
        selectBottomTab(R.id.navigation_home)
    }

    override fun onStartLesson() {
        selectBottomTab(R.id.navigation_path)
    }

    override fun onOpenLessonFromPath() {
        showLesson()
    }

    override fun onOpenMatchPairs() {
        showLesson()
    }

    override fun onOpenSpeakPractice() {
        Toast.makeText(this, R.string.practice_speak_coming_soon, Toast.LENGTH_SHORT).show()
    }

    override fun onOpenErrorReview() {
        if (WoofieRepository.recentMistakes.isEmpty()) {
            Toast.makeText(this, R.string.practice_no_errors_yet, Toast.LENGTH_SHORT).show()
            return
        }
        showLesson()
    }

    override fun onOpenProgress() {
        selectBottomTab(R.id.navigation_progress)
    }

    override fun onLessonFinished(correctAnswers: Int, totalAnswers: Int) {
        WoofieRepository.registerLessonResult(
            correctAnswers = correctAnswers,
            totalAnswers = totalAnswers
        )
        selectBottomTab(R.id.navigation_progress)
    }

    override fun onBackToHome() {
        selectBottomTab(R.id.navigation_home)
    }

    override fun onRestartPlan() {
        WoofieRepository.profile = null
        WoofieRepository.lastResultLabel = null
        WoofieRepository.lastEarnedXp = 0
        WoofieRepository.lastLessonPassed = false
        showOnboarding()
    }

    private fun showMainNavigation() {
        bottomNavigation.visibility = View.VISIBLE
    }

    private fun setupBottomNavigationMenu() {
        val menu = bottomNavigation.menu
        menu.clear()
        menu.add(Menu.NONE, R.id.navigation_home, 0, getString(R.string.nav_home))
            .setIcon(android.R.drawable.ic_menu_view)
        menu.add(Menu.NONE, R.id.navigation_path, 1, getString(R.string.nav_path))
            .setIcon(android.R.drawable.ic_menu_directions)
        menu.add(Menu.NONE, R.id.navigation_practice, 2, getString(R.string.nav_practice))
            .setIcon(android.R.drawable.ic_menu_edit)
        menu.add(Menu.NONE, R.id.navigation_vocabulary, 3, getString(R.string.nav_vocabulary))
            .setIcon(android.R.drawable.ic_menu_agenda)
        menu.add(Menu.NONE, R.id.navigation_progress, 4, getString(R.string.nav_progress))
            .setIcon(android.R.drawable.ic_menu_myplaces)
    }

    private fun hideMainNavigation() {
        bottomNavigation.visibility = View.GONE
    }

    private fun selectBottomTab(itemId: Int) {
        if (bottomNavigation.selectedItemId == itemId) {
            when (itemId) {
                R.id.navigation_home -> showHome()
                R.id.navigation_path -> showLessonPath()
                R.id.navigation_practice -> showPracticeCenter()
                R.id.navigation_vocabulary -> showVocabulary()
                R.id.navigation_progress -> showProgress()
            }
            return
        }
        suppressNavSelectionCallback = true
        bottomNavigation.selectedItemId = itemId
        suppressNavSelectionCallback = false
        when (itemId) {
            R.id.navigation_home -> showHome()
            R.id.navigation_path -> showLessonPath()
            R.id.navigation_practice -> showPracticeCenter()
            R.id.navigation_vocabulary -> showVocabulary()
            R.id.navigation_progress -> showProgress()
        }
    }

    private fun showOnboarding() {
        hideMainNavigation()
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, OnboardingFragment())
            .commit()
    }

    private fun showHome() {
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, HomeFragment())
            .commit()
    }

    private fun showLesson() {
        supportFragmentManager.beginTransaction()
            .setCustomAnimations(
                R.anim.woofie_enter_right,
                R.anim.woofie_exit_left,
                R.anim.woofie_enter_left,
                R.anim.woofie_exit_right
            )
            .replace(R.id.fragmentContainer, LessonFragment())
            .commit()
    }

    private fun showPracticeCenter() {
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, PracticeCenterFragment())
            .commit()
    }

    private fun showLessonPath() {
        supportFragmentManager.beginTransaction()
            .setCustomAnimations(
                R.anim.woofie_enter_right,
                R.anim.woofie_exit_left,
                R.anim.woofie_enter_left,
                R.anim.woofie_exit_right
            )
            .replace(R.id.fragmentContainer, LessonPathFragment())
            .commit()
    }

    private fun showVocabulary() {
        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, VocabularyFragment())
            .commit()
    }

    private fun showProgress(
        resultLabel: String? = null,
        earnedXp: Int = WoofieRepository.lastEarnedXp,
        passedLesson: Boolean = WoofieRepository.lastLessonPassed
    ) {
        val fragment = ProgressFragment.newInstance(
            resultLabel = resultLabel ?: WoofieRepository.lastResultLabel.orEmpty(),
            earnedXp = earnedXp,
            passedLesson = passedLesson
        )

        supportFragmentManager.beginTransaction()
            .replace(R.id.fragmentContainer, fragment)
            .commit()
    }
}

package com.example.woofie.data
import com.example.woofie.model.Profession import com.example.woofie.model.QuizQuestion import com.example.woofie.model.UserProfile
object WoofieRepository { data class VocabularyTerm( val word: String, val translation: String, val example: String )
data class LessonStage( val number: Int, val title: String, val lessonRange: IntRange )
data class LessonOutcome( val correctAnswers: Int, val totalQuestions: Int, val earnedXp: Int, val passed: Boolean ) { val scoreLabel: String = "$correctAnswers/$totalQuestions" }
const val LESSON_SIZE = 8 const val MIN_CORRECT_TO_PASS = 6
var profile: UserProfile? = null var lastResultLabel: String? = null var lastEarnedXp: Int = 0 var lastLessonPassed: Boolean = false val recentMistakes: MutableList<String> = mutableListOf()
fun registerMistake(prompt: String) { recentMistakes.add(0, prompt) if (recentMistakes.size > 20) { recentMistakes.removeAt(recentMistakes.lastIndex) } }
fun getLessonStages(profession: Profession): List<LessonStage> { return when (profession) { Profession.IT -> listOf( LessonStage(1, "Entorno IT y componentes fisicos", 1..2), LessonStage(2, "Hardware en el trabajo", 3..4), LessonStage(3, "Redes y soporte tecnico", 5..6), LessonStage(4, "Frontend y colaboracion agil", 7..8) )
Profession.HEALTH -> listOf( LessonStage(1, "Comunicacion con pacientes", 1..2), LessonStage(2, "Signos vitales y seguimiento", 3..4), LessonStage(3, "Indicaciones y medicacion", 5..6), LessonStage(4, "Alta y coordinacion clinica", 7..8) )
Profession.SALES -> listOf( LessonStage(1, "Prospeccion y contexto comercial", 1..2), LessonStage(2, "Discovery y necesidades", 3..4), LessonStage(3, "Objecciones y propuesta", 5..6), LessonStage(4, "Cierre y seguimiento", 7..8) ) } }
fun getTotalLessons(profession: Profession): Int { return getLessonStages(profession).sumOf { stage -> stage.lessonRange.count() } }
fun getLessonConcept(profession: Profession, lessonNumber: Int): String { val concepts = when (profession) { Profession.IT -> listOf( "Ticket resuelto", "Standup bloqueos", "Deployment exitoso", "Logs de servidor", "Code review", "Rollback version", "Timeout de API", "Sprint planning" )
Profession.HEALTH -> listOf( "Tomar medicacion", "Comodidad del paciente", "Cita de seguimiento", "Calmar al paciente", "Signos vitales", "Reposo medico", "Instrucciones de alta", "Escala de dolor" )
Profession.SALES -> listOf( "Llamada de seguimiento", "Manejo de objeciones", "Propuesta de precios", "Agradecer reunion", "Discovery call", "Resumen por correo", "Decision maker", "Agendar demo" ) }
val index = lessonNumber - 1 return concepts.getOrElse(index) { "Concepto ${lessonNumber}" } }
fun getVocabularyTerms(profession: Profession): List<VocabularyTerm> { return when (profession) { Profession.IT -> listOf( VocabularyTerm("Pull request", "solicitud de revision", "Please review my pull request before noon."), VocabularyTerm("Bug fix", "correccion de error", "We pushed a bug fix to production."), VocabularyTerm("Deploy", "desplegar", "We deploy every Friday."), VocabularyTerm("Deadline", "fecha limite", "The deadline is next Tuesday."), VocabularyTerm("Frontend", "capa visual", "I work mostly on frontend tasks."), VocabularyTerm("API", "interfaz de servicios", "The API returns a timeout error.") )
Profession.HEALTH -> listOf( VocabularyTerm("Vitals", "signos vitales", "I will check your vitals now."), VocabularyTerm("Diagnosis", "diagnostico", "The diagnosis is clear."), VocabularyTerm("Follow-up", "seguimiento", "You need a follow-up appointment."), VocabularyTerm("Prescription", "receta medica", "Your prescription is ready."), VocabularyTerm("Dosage", "dosis", "Take the correct dosage every day."), VocabularyTerm("Discharge", "alta medica", "The patient received discharge instructions.") )
Profession.SALES -> listOf( VocabularyTerm("Lead", "cliente potencial", "This lead is ready for a demo."), VocabularyTerm("Pitch", "presentacion comercial", "Our sales pitch is concise."), VocabularyTerm("Proposal", "propuesta", "I sent the pricing proposal yesterday."), VocabularyTerm("Objection", "objecion", "Handle each objection with empathy."), VocabularyTerm("Closing", "cierre de venta", "We are close to closing this deal."), VocabularyTerm("Upsell", "venta adicional", "Upsell only when it adds value.") ) } }
fun getQuestionsFor(profession: Profession): List<QuizQuestion> { return when (profession) { Profession.IT -> listOf( QuizQuestion( prompt = "How do you say 'ticket resuelto' in a sprint update?", options = listOf("Solved ticket", "Strong ticket", "Ticket weather"), correctIndex = 0 ), QuizQuestion( prompt = "Choose the best phrase for daily standup:", options = listOf("I blocked yesterday", "I am blocked by API", "I was coding table"), correctIndex = 1 ), QuizQuestion( prompt = "What means 'deployment completed successfully'?", options = listOf("La reunion fue cancelada", "El despliegue termino bien", "No hay conexion"), correctIndex = 1 ), QuizQuestion( prompt = "Translate: 'Necesito revisar los logs del servidor'.", options = listOf("I need to review the server logs", "I need to paint the server", "I need to close the office"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase for code review request:", options = listOf("Could you review this pull request?", "Could you remove this keyboard?", "Could you call my manager now?"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'rollback to previous version'?", options = listOf("Avanzar a la siguiente version", "Volver a la version anterior", "Eliminar el proyecto"), correctIndex = 1 ), QuizQuestion( prompt = "Translate: 'La API responde con timeout'.", options = listOf("The API responds with a timeout", "The API responds with a smile", "The API responds with a shortcut"), correctIndex = 0 ), QuizQuestion( prompt = "Best sentence for sprint planning:", options = listOf("Let's estimate these tasks", "Let's cancel all tasks", "Let's ship without tests"), correctIndex = 0 ) )
Profession.HEALTH -> listOf( QuizQuestion( prompt = "Translate: 'Tome este medicamento dos veces al dia'", options = listOf( "Take this medicine twice a day", "Drink this medicine all week", "Call this medicine now" ), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase to ask patient comfort:", options = listOf("Are you feeling comfortable?", "You are fine now?", "Can you sleep medicine?"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'follow-up appointment'?", options = listOf("Cita de seguimiento", "Cita urgente", "Examen de sangre"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Respire profundo, todo esta bajo control'.", options = listOf("Breathe deeply, everything is under control", "Run quickly, nothing is ready", "Drink this later"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase before checking vital signs:", options = listOf("I will check your vital signs", "I will cancel your room", "I will call your office"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Debe guardar reposo por tres dias'.", options = listOf("You should rest for three days", "You should walk for three hours", "You should skip your meal"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'discharge instructions'?", options = listOf("Instrucciones de alta", "Instrucciones de ingreso", "Resultado de radiografia"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase for pain scale question:", options = listOf("How would you rate your pain from 1 to 10?", "Can you pay now?", "Do you need a new room key?"), correctIndex = 0 ) )
Profession.SALES -> listOf( QuizQuestion( prompt = "Translate: 'Podemos agendar una llamada de seguimiento'", options = listOf( "Can we schedule a follow-up call?", "Can we close now?", "Can we buy this later?" ), correctIndex = 0 ), QuizQuestion( prompt = "Choose the best sentence for objection handling:", options = listOf("I understand your concern", "You are wrong", "This is impossible"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'pricing proposal attached'?", options = listOf("Propuesta de precios adjunta", "Cliente no responde", "Producto agotado"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Gracias por tu tiempo en la reunion'.", options = listOf("Thank you for your time in the meeting", "You are late for the meeting", "Let's stop this forever"), correctIndex = 0 ), QuizQuestion( prompt = "Best opening for discovery call:", options = listOf("Can you tell me about your current process?", "Can you buy now in one minute?", "Can you send money first?"), correctIndex = 0 ), QuizQuestion( prompt = "Translate: 'Te envio un resumen por correo'.", options = listOf("I will send you a summary by email", "I will send you a car by noon", "I will send you a voice note to HR"), correctIndex = 0 ), QuizQuestion( prompt = "What means 'decision-maker'?", options = listOf("Persona que toma la decision", "Persona que guarda facturas", "Persona que recibe paquetes"), correctIndex = 0 ), QuizQuestion( prompt = "Best phrase to schedule next step:", options = listOf("Does next Tuesday work for a demo?", "Do you want to cancel all meetings?", "Can you transfer now?"), correctIndex = 0 ) ) } }
fun registerLessonResult(correctAnswers: Int, totalAnswers: Int = LESSON_SIZE): LessonOutcome { val currentProfile = profile ?: return LessonOutcome( correctAnswers = correctAnswers, totalQuestions = totalAnswers, earnedXp = 0, passed = false )
val passedLesson = correctAnswers >= MIN_CORRECT_TO_PASS val earnedXp = (correctAnswers * 12) + if (passedLesson) 40 else 10
currentProfile.completedLessons += 1 currentProfile.xp += earnedXp currentProfile.streak += 1 lastResultLabel = "$correctAnswers/$totalAnswers" lastEarnedXp = earnedXp lastLessonPassed = passedLesson
return LessonOutcome( correctAnswers = correctAnswers, totalQuestions = totalAnswers, earnedXp = earnedXp, passed = passedLesson ) } }

package com.example.woofie.ui

import android.content.Context
import android.os.Bundle
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.RadioButton
import android.widget.RadioGroup
import android.widget.TextView
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.model.QuizQuestion
import com.example.woofie.ui.common.applySystemBarsPadding
import com.google.android.material.button.MaterialButton
import com.google.android.material.card.MaterialCardView
import com.google.android.material.progressindicator.LinearProgressIndicator

class LessonFragment : Fragment(R.layout.fragment_lesson) {

    interface Listener {
        fun onLessonFinished(correctAnswers: Int, totalAnswers: Int)
    }

    private var listener: Listener? = null
    private var questions: List<QuizQuestion> = emptyList()
    private var currentIndex = 0
    private var correctAnswers = 0
    private var hasAnsweredCurrent = false

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()
        val profile = WoofieRepository.profile ?: return
        questions = WoofieRepository.getQuestionsFor(profile.profession)

        val progressText: TextView = view.findViewById(R.id.textLessonProgress)
        val progressBar: LinearProgressIndicator = view.findViewById(R.id.lessonProgressBar)
        val questionText: TextView = view.findViewById(R.id.textLessonQuestion)
        val resultText: TextView = view.findViewById(R.id.textLessonResult)
        val wrongFeedbackCard: MaterialCardView = view.findViewById(R.id.cardWrongFeedback)
        val wrongFeedbackBody: TextView = view.findViewById(R.id.textWrongFeedbackBody)
        val wrongFeedbackHint: TextView = view.findViewById(R.id.textWrongFeedbackHint)
        val optionsGroup: RadioGroup = view.findViewById(R.id.optionsGroup)
        val optionOne: RadioButton = view.findViewById(R.id.optionOne)
        val optionTwo: RadioButton = view.findViewById(R.id.optionTwo)
        val optionThree: RadioButton = view.findViewById(R.id.optionThree)
        val buttonCheck: MaterialButton = view.findViewById(R.id.buttonCheck)
        val options = listOf(optionOne, optionTwo, optionThree)

        val optionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        val resultAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_result_fade_in)
        val questionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_slide_up)
        val shakeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_shake)
        var isFeedbackExpanded = false

        progressBar.max = questions.size

        fun animateOptionsEntry() {
            options.forEachIndexed { index, option ->
                option.alpha = 0f
                option.translationY = 16f
                option.animate()
                    .alpha(1f)
                    .translationY(0f)
                    .setStartDelay((index * 70).toLong())
                    .setDuration(180)
                    .start()
            }
        }

        fun collapseFeedback() {
            isFeedbackExpanded = false
            wrongFeedbackBody.maxLines = 2
            wrongFeedbackHint.text = getString(R.string.lesson_feedback_expand)
        }

        fun hideFeedback() {
            wrongFeedbackCard.visibility = View.GONE
            collapseFeedback()
        }

        fun showWrongFeedback(selectedOption: String, correctOption: String) {
            wrongFeedbackBody.text = getString(
                R.string.lesson_feedback_body,
                selectedOption,
                correctOption
            )
            collapseFeedback()
            wrongFeedbackCard.visibility = View.VISIBLE
            wrongFeedbackCard.startAnimation(resultAnim)
        }

        fun bindQuestion() {
            val question = questions[currentIndex]
            progressText.text = getString(R.string.lesson_progress, currentIndex + 1, questions.size)
            progressBar.progress = currentIndex + 1
            questionText.text = question.prompt
            questionText.startAnimation(questionAnim)
            optionOne.text = question.options[0]
            optionTwo.text = question.options[1]
            optionThree.text = question.options[2]
            optionsGroup.clearCheck()
            options.forEach { option ->
                option.isEnabled = true
                option.setBackgroundResource(R.drawable.lesson_option_selector)
            }
            resultText.text = ""
            hideFeedback()
            buttonCheck.text = getString(R.string.lesson_check)
            hasAnsweredCurrent = false
            animateOptionsEntry()
        }

        fun showAnswerState(selectedIndex: Int, correctIndex: Int) {
            options.forEachIndexed { index, radioButton ->
                val background = when {
                    index == correctIndex -> R.drawable.lesson_option_correct
                    index == selectedIndex -> R.drawable.lesson_option_incorrect
                    else -> R.drawable.lesson_option_idle
                }
                radioButton.setBackgroundResource(background)
                radioButton.isEnabled = false
            }
        }

        optionsGroup.setOnCheckedChangeListener { group, checkedId ->
            if (checkedId == View.NO_ID || hasAnsweredCurrent) return@setOnCheckedChangeListener
            group.findViewById<RadioButton>(checkedId)?.startAnimation(optionAnim)
        }

        wrongFeedbackCard.setOnClickListener {
            isFeedbackExpanded = !isFeedbackExpanded
            wrongFeedbackBody.maxLines = if (isFeedbackExpanded) Int.MAX_VALUE else 2
            wrongFeedbackHint.text = getString(
                if (isFeedbackExpanded) R.string.lesson_feedback_collapse
                else R.string.lesson_feedback_expand
            )
        }

        buttonCheck.setOnClickListener {
            it.animate().scaleX(0.96f).scaleY(0.96f).setDuration(70)
                .withEndAction {
                    it.animate().scaleX(1f).scaleY(1f).setDuration(90).start()
                }.start()

            if (buttonCheck.text == getString(R.string.lesson_next)) {
                currentIndex += 1
                if (currentIndex >= questions.size) {
                    listener?.onLessonFinished(correctAnswers, questions.size)
                } else {
                    bindQuestion()
                }
                return@setOnClickListener
            }

            val selectedId = optionsGroup.checkedRadioButtonId
            if (selectedId == View.NO_ID) {
                resultText.text = getString(R.string.lesson_select_option)
                resultText.startAnimation(resultAnim)
                optionsGroup.startAnimation(shakeAnim)
                return@setOnClickListener
            }

            val selectedIndex = when (selectedId) {
                R.id.optionOne -> 0
                R.id.optionTwo -> 1
                else -> 2
            }
            val currentQuestion = questions[currentIndex]
            val isCorrect = selectedIndex == currentQuestion.correctIndex
            if (isCorrect) correctAnswers += 1
            hasAnsweredCurrent = true
            showAnswerState(selectedIndex = selectedIndex, correctIndex = currentQuestion.correctIndex)

            resultText.text = if (isCorrect) {
                hideFeedback()
                getString(R.string.lesson_correct)
            } else {
                showWrongFeedback(
                    selectedOption = currentQuestion.options[selectedIndex],
                    correctOption = currentQuestion.options[currentQuestion.correctIndex]
                )
                getString(
                    R.string.lesson_incorrect,
                    currentQuestion.options[currentQuestion.correctIndex]
                )
            }
            resultText.startAnimation(resultAnim)
            if (!isCorrect) {
                view.findViewById<RadioButton>(selectedId)?.startAnimation(shakeAnim)
            }
            buttonCheck.text = getString(R.string.lesson_next)
        }

        bindQuestion()
    }
}

package com.example.woofie.ui
import android.content.Context import android.os.Bundle import android.view.View import android.view.animation.AnimationUtils import android.widget.RadioButton import android.widget.RadioGroup import android.widget.TextView import androidx.fragment.app.Fragment import com.example.woofie.R import com.example.woofie.data.WoofieRepository import com.example.woofie.model.QuizQuestion import com.example.woofie.ui.common.applySystemBarsPadding import com.google.android.material.button.MaterialButton import com.google.android.material.card.MaterialCardView import com.google.android.material.progressindicator.LinearProgressIndicator
class LessonFragment : Fragment(R.layout.fragment_lesson) {
interface Listener { fun onLessonFinished(correctAnswers: Int, totalAnswers: Int) }
private var listener: Listener? = null private var questions: List<QuizQuestion> = emptyList() private var currentIndex = 0 private var correctAnswers = 0 private var hasAnsweredCurrent = false
override fun onAttach(context: Context) { super.onAttach(context) listener = context as? Listener }
override fun onDetach() { super.onDetach() listener = null }
override fun onViewCreated(view: View, savedInstanceState: Bundle?) { view.applySystemBarsPadding() val profile = WoofieRepository.profile ?: return questions = WoofieRepository.getQuestionsFor(profile.profession)
val progressText: TextView = view.findViewById(R.id.textLessonProgress) val progressBar: LinearProgressIndicator = view.findViewById(R.id.lessonProgressBar) val questionText: TextView = view.findViewById(R.id.textLessonQuestion) val resultText: TextView = view.findViewById(R.id.textLessonResult) val wrongFeedbackCard: MaterialCardView = view.findViewById(R.id.cardWrongFeedback) val wrongFeedbackBody: TextView = view.findViewById(R.id.textWrongFeedbackBody) val wrongFeedbackHint: TextView = view.findViewById(R.id.textWrongFeedbackHint) val optionsGroup: RadioGroup = view.findViewById(R.id.optionsGroup) val optionOne: RadioButton = view.findViewById(R.id.optionOne) val optionTwo: RadioButton = view.findViewById(R.id.optionTwo) val optionThree: RadioButton = view.findViewById(R.id.optionThree) val buttonCheck: MaterialButton = view.findViewById(R.id.buttonCheck) val options = listOf(optionOne, optionTwo, optionThree)
val optionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop) val resultAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_result_fade_in) val questionAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_slide_up) val shakeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_shake) var isFeedbackExpanded = false
progressBar.max = questions.size
fun animateOptionsEntry() { options.forEachIndexed { index, option -> option.alpha = 0f option.translationY = 16f option.animate() .alpha(1f) .translationY(0f) .setStartDelay((index * 70).toLong()) .setDuration(180) .start() } }
fun collapseFeedback() { isFeedbackExpanded = false wrongFeedbackBody.maxLines = 2 wrongFeedbackHint.text = getString(R.string.lesson_feedback_expand) }
fun hideFeedback() { wrongFeedbackCard.visibility = View.GONE collapseFeedback() }
fun showWrongFeedback(selectedOption: String, correctOption: String) { wrongFeedbackBody.text = getString( R.string.lesson_feedback_body, selectedOption, correctOption ) collapseFeedback() wrongFeedbackCard.visibility = View.VISIBLE wrongFeedbackCard.startAnimation(resultAnim) }
fun bindQuestion() { val question = questions[currentIndex] progressText.text = getString(R.string.lesson_progress, currentIndex + 1, questions.size) progressBar.progress = currentIndex + 1 questionText.text = question.prompt questionText.startAnimation(questionAnim) optionOne.text = question.options[0] optionTwo.text = question.options[1] optionThree.text = question.options[2] optionsGroup.clearCheck() options.forEach { option -> option.isEnabled = true option.setBackgroundResource(R.drawable.lesson_option_selector) } resultText.text = "" hideFeedback() buttonCheck.text = getString(R.string.lesson_check) hasAnsweredCurrent = false animateOptionsEntry() }
fun showAnswerState(selectedIndex: Int, correctIndex: Int) { options.forEachIndexed { index, radioButton -> val background = when { index == correctIndex -> R.drawable.lesson_option_correct index == selectedIndex -> R.drawable.lesson_option_incorrect else -> R.drawable.lesson_option_idle } radioButton.setBackgroundResource(background) radioButton.isEnabled = false } }
optionsGroup.setOnCheckedChangeListener { group, checkedId -> if (checkedId == View.NO_ID || hasAnsweredCurrent) return@setOnCheckedChangeListener group.findViewById<RadioButton>(checkedId)?.startAnimation(optionAnim) }
wrongFeedbackCard.setOnClickListener { isFeedbackExpanded = !isFeedbackExpanded wrongFeedbackBody.maxLines = if (isFeedbackExpanded) Int.MAX_VALUE else 2 wrongFeedbackHint.text = getString( if (isFeedbackExpanded) R.string.lesson_feedback_collapse else R.string.lesson_feedback_expand ) }
buttonCheck.setOnClickListener { it.animate().scaleX(0.96f).scaleY(0.96f).setDuration(70) .withEndAction { it.animate().scaleX(1f).scaleY(1f).setDuration(90).start() }.start()
if (buttonCheck.text == getString(R.string.lesson_next)) { currentIndex += 1 if (currentIndex >= questions.size) { listener?.onLessonFinished(correctAnswers, questions.size) } else { bindQuestion() } return@setOnClickListener }
val selectedId = optionsGroup.checkedRadioButtonId if (selectedId == View.NO_ID) { resultText.text = getString(R.string.lesson_select_option) resultText.startAnimation(resultAnim) optionsGroup.startAnimation(shakeAnim) return@setOnClickListener }
val selectedIndex = when (selectedId) { R.id.optionOne -> 0 R.id.optionTwo -> 1 else -> 2 } val currentQuestion = questions[currentIndex] val isCorrect = selectedIndex == currentQuestion.correctIndex if (isCorrect) correctAnswers += 1 hasAnsweredCurrent = true showAnswerState(selectedIndex = selectedIndex, correctIndex = currentQuestion.correctIndex)
resultText.text = if (isCorrect) { hideFeedback() getString(R.string.lesson_correct) } else { WoofieRepository.registerMistake(currentQuestion.prompt) showWrongFeedback( selectedOption = currentQuestion.options[selectedIndex], correctOption = currentQuestion.options[currentQuestion.correctIndex] ) getString( R.string.lesson_incorrect, currentQuestion.options[currentQuestion.correctIndex] ) } resultText.startAnimation(resultAnim) if (!isCorrect) { view.findViewById<RadioButton>(selectedId)?.startAnimation(shakeAnim) } buttonCheck.text = getString(R.string.lesson_next) }
bindQuestion() } }

package com.example.woofie.ui

import android.annotation.SuppressLint
import android.animation.ObjectAnimator
import android.animation.ValueAnimator
import android.content.Context
import android.os.Bundle
import android.view.MotionEvent
import android.view.LayoutInflater
import android.view.View
import android.view.animation.AnimationUtils
import android.widget.FrameLayout
import android.widget.LinearLayout
import android.widget.TextView
import androidx.core.content.ContextCompat
import androidx.fragment.app.Fragment
import com.example.woofie.R
import com.example.woofie.data.WoofieRepository
import com.example.woofie.ui.common.applySystemBarsPadding

class LessonPathFragment : Fragment(R.layout.fragment_lesson_path) {

    interface Listener {
        fun onOpenLessonFromPath()
    }

    private var listener: Listener? = null

    override fun onAttach(context: Context) {
        super.onAttach(context)
        listener = context as? Listener
    }

    override fun onDetach() {
        super.onDetach()
        listener = null
    }

    @SuppressLint("ClickableViewAccessibility")
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        view.applySystemBarsPadding()
        val profile = WoofieRepository.profile ?: return
        val container: LinearLayout = view.findViewById(R.id.pathContainer)
        val trailContainer: LinearLayout = view.findViewById(R.id.pathTrailContainer)
        val nodeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop)
        container.removeAllViews()
        trailContainer.removeAllViews()

        val stages = WoofieRepository.getLessonStages(profile.profession)
        val totalNodes = WoofieRepository.getTotalLessons(profile.profession)
        val completed = profile.completedLessons.coerceAtMost(totalNodes)
        val nextUnlocked = (completed + 1).coerceAtMost(totalNodes)
        val currentNode = if (nextUnlocked <= totalNodes) nextUnlocked else totalNodes

        fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

        repeat(totalNodes) { index ->
            val number = index + 1
            val isDone = number <= completed
            val isCurrentTrail = number == currentNode

            val chip = TextView(requireContext()).apply {
                text = number.toString()
                textSize = 13f
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                gravity = android.view.Gravity.CENTER
                layoutParams = LinearLayout.LayoutParams(dp(30), dp(30))
                background = when {
                    isDone -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrentTrail -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                setTextColor(
                    if (isDone) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
            }
            trailContainer.addView(chip)

            if (number < totalNodes) {
                val connector = View(requireContext()).apply {
                    layoutParams = LinearLayout.LayoutParams(dp(18), dp(4)).also { params ->
                        params.leftMargin = dp(6)
                        params.rightMargin = dp(6)
                    }
                    setBackgroundColor(
                        ContextCompat.getColor(
                            requireContext(),
                            if (number < currentNode) R.color.woofie_primary else R.color.woofie_gray_200
                        )
                    )
                }
                trailContainer.addView(connector)
            }
        }

        stages.forEach { stage ->
            val stageTitle = TextView(requireContext()).apply {
                text = "Etapa ${stage.number}: ${stage.title}"
                setTextColor(ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark))
                setTypeface(typeface, android.graphics.Typeface.BOLD)
                textSize = 16f
                setPadding(dp(4), dp(10), dp(4), dp(8))
            }
            container.addView(stageTitle)

            stage.lessonRange.forEach { nodeNumber ->
                val index = nodeNumber - 1
                val nodeView = LayoutInflater.from(requireContext())
                    .inflate(R.layout.item_lesson_path_node, container, false)

                val anchor: FrameLayout = nodeView.findViewById(R.id.nodeAnchor)
                val badge: TextView = nodeView.findViewById(R.id.textNodeBadge)
                val connector: View = nodeView.findViewById(R.id.pathConnector)
                val shadow: View = nodeView.findViewById(R.id.nodeShadow)

                val isCompleted = nodeNumber <= completed
                val isUnlocked = nodeNumber <= nextUnlocked
                val isCurrent = nodeNumber == currentNode

                badge.text = nodeNumber.toString()
                badge.background = when {
                    isCompleted -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed)
                    isCurrent -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current)
                    isUnlocked -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_unlocked)
                    else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked)
                }
                badge.setTextColor(
                    if (isCompleted) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark)
                    else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)
                )
                badge.alpha = if (isUnlocked) 1f else 0.65f
                badge.isEnabled = isUnlocked
                shadow.alpha = if (isUnlocked) 1f else 0.45f
                badge.scaleX = if (isCurrent) 1.08f else 1f
                badge.scaleY = if (isCurrent) 1.08f else 1f

                val anchorParams = anchor.layoutParams as LinearLayout.LayoutParams
                val offsetX = when (index % 6) {
                    0 -> -120f
                    1 -> -26f
                    2 -> 86f
                    3 -> 120f
                    4 -> 18f
                    else -> -92f
                }
                anchor.translationX = offsetX
                anchor.layoutParams = anchorParams

                connector.visibility = if (nodeNumber == totalNodes) View.GONE else View.VISIBLE
                if (nodeNumber < totalNodes) {
                    val nextOffsetX = when ((index + 1) % 6) {
                        0 -> -120f
                        1 -> -26f
                        2 -> 86f
                        3 -> 120f
                        4 -> 18f
                        else -> -92f
                    }
                    connector.translationX = (nextOffsetX - offsetX) / 2f
                    connector.rotation = (nextOffsetX - offsetX) / 10f
                }

                if (isUnlocked) {
                    val floatAnim = ObjectAnimator.ofFloat(badge, View.TRANSLATION_Y, 0f, -8f, 0f).apply {
                        duration = 1800
                        startDelay = index * 100L
                        repeatCount = ValueAnimator.INFINITE
                    }
                    floatAnim.start()

                    badge.setOnTouchListener { touchedView, event ->
                        when (event.actionMasked) {
                            MotionEvent.ACTION_DOWN -> {
                                touchedView.animate().scaleX(0.92f).scaleY(0.92f).setDuration(80).start()
                                true
                            }

                            MotionEvent.ACTION_UP -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                touchedView.performClick()
                                true
                            }

                            MotionEvent.ACTION_CANCEL -> {
                                touchedView.animate().scaleX(1f).scaleY(1f).setDuration(120).start()
                                true
                            }

                            else -> false
                        }
                    }

                    badge.setOnClickListener {
                        it.startAnimation(nodeAnim)
                        listener?.onOpenLessonFromPath()
                    }
                }

                badge.elevation = if (isCurrent) 10f else 6f

                nodeView.startAnimation(nodeAnim)
                container.addView(nodeView)
            }
        }
    }
}

