@SuppressLint("ClickableViewAccessibility") override fun onViewCreated(view: View, savedInstanceState: Bundle?) { view.applySystemBarsPadding() val profile = WoofieRepository.profile ?: return val container: LinearLayout = view.findViewById(R.id.pathContainer) val trailContainerId = resources.getIdentifier("pathTrailContainer", "id", requireContext().packageName) val trailContainer: LinearLayout? = if (trailContainerId != 0) view.findViewById(trailContainerId) else null val nodeAnim = AnimationUtils.loadAnimation(requireContext(), R.anim.woofie_option_pop) container.removeAllViews() trailContainer?.removeAllViews()
val stages = WoofieRepository.getLessonStages(profile.profession) val totalNodes = WoofieRepository.getTotalLessons(profile.profession) val completed = profile.completedLessons.coerceAtMost(totalNodes) val nextUnlocked = (completed + 1).coerceAtMost(totalNodes) val currentNode = if (nextUnlocked <= totalNodes) nextUnlocked else totalNodes
fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()
repeat(totalNodes) { index -> val number = index + 1 val isDone = number <= completed val isCurrentTrail = number == currentNode
val chip = TextView(requireContext()).apply { text = number.toString() textSize = 13f setTypeface(typeface, android.graphics.Typeface.BOLD) gravity = android.view.Gravity.CENTER layoutParams = LinearLayout.LayoutParams(dp(30), dp(30)) background = when { isDone -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_completed) isCurrentTrail -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_current) else -> ContextCompat.getDrawable(requireContext(), R.drawable.lesson_node_locked) } setTextColor( if (isDone) ContextCompat.getColor(requireContext(), R.color.woofie_text_on_dark) else ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark) ) } trailContainer?.addView(chip)
if (number < totalNodes) { val connector = View(requireContext()).apply { layoutParams = LinearLayout.LayoutParams(dp(18), dp(4)).also { params -> params.leftMargin = dp(6) params.rightMargin = dp(6) } setBackgroundColor( ContextCompat.getColor( requireContext(), if (number < currentNode) R.color.woofie_primary else R.color.woofie_gray_200 ) ) } trailContainer?.addView(connector) } }
stages.forEach { stage -> val stageTitle = TextView(requireContext()).apply { text = getString(R.string.lesson_path_stage_title, stage.number, stage.title) setTextColor(ContextCompat.getColor(requireContext(), R.color.woofie_primary_dark)) setTypeface(typeface, android.graphics.Typeface.BOLD) textSize = 16f setPadding(dp(4), dp(10), dp(4), dp(8)) } container.addView(stageTitle)
